const CustomerMessages = () => {
  return (
    <div>
      <h1 className="text-2xl font-semibold text-gray-900">Messages</h1>
      <p className="mt-4 text-gray-600">Your messages will appear here. Coming soon...</p>
    </div>
  );
};

export default CustomerMessages;
